/**
 * Real Star Catalog — HYG v4.2 (Hipparcos-Yale-Gliese), mag < 6.5
 * 8921 naked-eye visible stars, sorted by magnitude (brightest first).
 * License: CC-BY-SA 4.0 (astronexus.com)
 *
 * Binary format: Float32LE, 5 values per star:
 *   [x, y, z, magnitude, B-V_color_index]
 * where (x,y,z) is a J2000 equatorial unit vector.
 */

const HYG_B64 = "";

let _decoded: Float32Array | null = null;

function decode(): Float32Array {
  if (_decoded) return _decoded;
  const bin = atob(HYG_B64);
  const buf = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i);
  _decoded = new Float32Array(buf.buffer);
  return _decoded;
}

export const STAR_COUNT = 8921;
export const FIELDS_PER_STAR = 5;

/** Get the full decoded Float32Array: [x0,y0,z0,mag0,ci0, x1,y1,z1,mag1,ci1, ...] */
export function getStarData(): Float32Array {
  return decode();
}

/**
 * Convert B-V color index to approximate RGB.
 * Based on Ballesteros (2012) blackbody formula.
 */
export function bvToRGB(bv: number): [number, number, number] {
  // Clamp to typical range
  bv = Math.max(-0.4, Math.min(2.0, bv));
  // Approximate temperature from B-V
  const t = 4600 * (1 / (0.92 * bv + 1.7) + 1 / (0.92 * bv + 0.62));
  // Planckian locus approximation (Ballesteros)
  let r: number, g: number, b: number;
  // Red
  if (t <= 6600) { r = 1.0; }
  else { r = Math.pow((t - 6000) / 1000, -0.1332047592); r = Math.min(1, Math.max(0, r)); }
  // Green
  if (t <= 6600) { g = 0.39008157876 * Math.log(t / 100) - 0.63184144378; }
  else { g = 1.29293618606 * Math.pow(t / 100 - 60, -0.0755148492); }
  g = Math.min(1, Math.max(0, g));
  // Blue
  if (t >= 6600) { b = 1.0; }
  else if (t <= 1900) { b = 0.0; }
  else { b = 0.54320678911 * Math.log(t / 100 - 10) - 1.19625408914; b = Math.min(1, Math.max(0, b)); }
  return [r, g, b];
}
